import{_ as e,c as i,o as l,ae as r}from"./chunks/framework.B7Y1jjX-.js";const u=JSON.parse('{"title":"SEO 搜索引擎优化","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/浏览器与环境/SEO 搜索引擎优化.md","filePath":"generated-notes/前端/浏览器与环境/SEO 搜索引擎优化.md"}'),t={name:"generated-notes/前端/浏览器与环境/SEO 搜索引擎优化.md"};function o(h,a,d,n,s,p){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="seo-搜索引擎优化" tabindex="-1">SEO 搜索引擎优化 <a class="header-anchor" href="#seo-搜索引擎优化" aria-label="Permalink to &quot;SEO 搜索引擎优化&quot;">​</a></h1><p>Search Engine Optimization</p><h2 id="_0-搜索引擎原理" tabindex="-1">0 搜索引擎原理 <a class="header-anchor" href="#_0-搜索引擎原理" aria-label="Permalink to &quot;0 搜索引擎原理&quot;">​</a></h2><p>一种负责将用户的搜索信息展示的工具</p><h3 id="基本原理简介" tabindex="-1">基本原理简介 <a class="header-anchor" href="#基本原理简介" aria-label="Permalink to &quot;基本原理简介&quot;">​</a></h3><p>搜索引擎过程非常复杂，我们这里只能以最简单的流程来介绍搜索引擎是怎么实现网页排名的。 搜索引擎的工作过程大体可以分为三个阶段：</p><ol><li>爬行和抓取：搜索引擎通过跟踪链接访问网页、获得页面 HTML 代码并存入数据库。</li><li>预处理（索引）：索引程序对抓取来的页面数据进行文字提取、中文分词、索引等处理，以备排名程序调用。</li><li>排名：用户输入关键词后，排名程序调用索引数据库，计算相关性，然后按照一个的格式生成搜索结果页面。</li></ol><h4 id="第一步-爬行和抓取" tabindex="-1">第一步：爬行和抓取 <a class="header-anchor" href="#第一步-爬行和抓取" aria-label="Permalink to &quot;第一步：爬行和抓取&quot;">​</a></h4><p>爬行和抓取是搜索引擎工作的第一步，完成<strong>数据收集</strong>的任务。</p><h5 id="spider" tabindex="-1">spider <a class="header-anchor" href="#spider" aria-label="Permalink to &quot;spider&quot;">​</a></h5><p>搜索引擎用来爬行和抓取页面的程序叫做也就是我们熟知的蜘蛛（spider），也称为机器人（bot）。spider访问网站页面类似于普通用户使用的浏览器。spider 发出页面访问请求后，服务器返回 HTML 代码，spider 把收到的程序存入原始页面数据库。为了提高爬行和抓取速度，搜索引擎通常或多个spider并行爬行。</p><p>&gt;爬虫开始会从一个网页爬取信息，爬取到其他的链接后就可以跳转到其他的网页，直到爬取到指定的信息。一般半个月，你的网页就会被收录。</p><p>spider 访问任何一个网站时，都会先访问该网站根目录下的 rotbots.txt 文件。该文件可以告诉 spider 哪些文件或目录可以抓取或者禁止抓取。 和不同的浏览器 UA 不同一样，不同厂商的 spider 也带有特定代理的名称。</p><h5 id="跟踪链接" tabindex="-1">跟踪链接 <a class="header-anchor" href="#跟踪链接" aria-label="Permalink to &quot;跟踪链接&quot;">​</a></h5><p>为了抓取网上尽可能多的页面，spider 会跟踪网页上的链接，从一个页面爬到下一个页面，就好像蜘蛛在蜘蛛网上爬行一样。 爬行遍历有两种策略：</p><ul><li>深度优先：spider 沿着页面的链接一直爬取，直到该页面没有其他链接为止</li><li>广度优先：spider 在一个页面发现多个链接，先把这页面的所有第一层链接都遍历完，再继续第二层链接遍历</li></ul><p>程序猿肯定对这两个遍历算法很熟悉啦。 理论上无论是深度优先还是广度优先，只要给 spider 足够的时间，总是能把互联网上所有的页面链接都爬取完。但实际情况并不是这样，由于各种资源的限制，搜索引擎也只是爬行和收录互联网的一部分。</p><p><strong>所以通常 spider 都是深度优先和广度优先混合使用</strong>。</p><h5 id="吸引蜘蛛" tabindex="-1">吸引蜘蛛 <a class="header-anchor" href="#吸引蜘蛛" aria-label="Permalink to &quot;吸引蜘蛛&quot;">​</a></h5><p>通过上面的介绍可以知道，spider 不可能将所有的页面都收录，因此 SEO 就是要通过各种手段，吸引 spider 爬行收录自己网站更多的页面。既然不能所有页面都收录，那么 spider 肯定是尽量抓取重要页面。那么 spider 是如何判断哪些页面重要？有几个影响因素：</p><ul><li>网站和页面权重。质量高，资格老的网站权重高。</li><li>页面更新度。更新频率高的网站权重高。</li><li>导入的链接。无论是外部链接还是内部链接，要被 spider 抓取，就必须要有导入链接进入页面。高质量的导入链接也经常使页面上的导出链接被爬行深度增加。</li><li>与首页的点击距离。一般来说，网站最高的权重就是首页，大部分外链都是指向首页，spider 访问最频繁的也是首页。所以离首页越近的页面，权重也相对更高，被 spider 爬行的机会也越大。</li></ul><h5 id="地址库" tabindex="-1">地址库 <a class="header-anchor" href="#地址库" aria-label="Permalink to &quot;地址库&quot;">​</a></h5><p>为了避免重复爬行和抓取网址，搜索引擎会建立一个地址库，记录已经被发现还没有抓取的页面，以及已经被抓取的页面。通过地址库会有几个来源：</p><ul><li>人工录入的种子网站</li><li>spider 爬取页面后，解析出网址，与地址库对比。如果不存在，则存入</li><li>站长通过搜索引擎网页提交网址（一般个人博客或网站都采用这种方式）</li></ul><h5 id="文件存储" tabindex="-1">文件存储 <a class="header-anchor" href="#文件存储" aria-label="Permalink to &quot;文件存储&quot;">​</a></h5><p>spider 抓取的数据存入原始页面数据库。其中的页面数据与用户浏览器得到的 HTML 是完全一样。</p><h5 id="爬行时的复制内容检测" tabindex="-1">爬行时的复制内容检测 <a class="header-anchor" href="#爬行时的复制内容检测" aria-label="Permalink to &quot;爬行时的复制内容检测&quot;">​</a></h5><p>检测并删除复制内容是在预处理的步骤处理掉。不过 spider 在爬行的时候也会进行一定程度的复制内容检测。权重低，而大量抄袭复制内容的网站，spider 可能就不再继续爬行了。这也是为什么说一个网站需要原创内容的原因。</p><h4 id="第二步-预处理-索引" tabindex="-1">第二步：预处理（索引） <a class="header-anchor" href="#第二步-预处理-索引" aria-label="Permalink to &quot;第二步：预处理（索引）&quot;">​</a></h4><p>预处理有时候也称为<strong>索引</strong>。因为索引是预处理中最主要的步骤。预处理有几个步骤：</p><ol><li>提取文字。搜索引擎会提取页面的可见文字以及特殊的包含文字信息的代码，如 Meta 标签、图片Alt属性、超链接锚文字等。</li><li>分词，不同的语言有不同的分词如中文分词，英文分词。对第一步提取的文字进行分词。不同的搜索引擎使用的分词算法不同，会有差异。</li><li>去停止词。无论中文还是英文，都会有一些频率高，对内容没有影响的词。如语气词、感叹词，介词、副词等。搜索引擎会在索引页面之前去除这些词。</li><li>消除噪声。绝大部分页面还有一部分内容对页面主题也没有贡献。比如版权声明文字，导航条等。以博客为例，每个页面几乎都会有的文章分类，历史导航等信息，都是与页面主题无关的。这些都是属于噪音，需要消除掉。</li><li>去重。同一篇文章经常会重复出现在不同的网站及同一个网站的不同网址，搜索引擎并不喜欢这种重复的内容，所以搜索引擎会对这部分内容进行去重。</li><li>正向索引。也称索引。经过前面文字提取、分词、消噪、去重后，搜索引擎得到的就是独特的，能反映页面主体内容，以词为单位的内容。接下来搜索引擎索引程序就可以提取关键词，按照分词程序划分好的词，把页面转换为一个关键词组成的集合，同时记录每一个关键词在页面上的出现频率、出现次数、格式、位置。然后把这些页面及关键词形成的结构存储进索引库。</li><li>倒排索引。正向索引还不能直接用于关键词排名。搜索引擎还需要把正向索引数据库重新构造为倒排索引，<strong>把文件对应到关键词的映射转换为关键词到文件映射</strong>。这样在搜索关键词的时候，排序程序就在倒排索引中定位到这个关键词，就可以马上找出这个关键词所有的文件。</li><li>链接关系计算。链接关系计算也是预处理重要的一部分。搜索引擎在抓取页面内容后，必须事前计算出：页面上有哪些链接指向哪些其他页面，每个页面都有哪些导入链接，链接使用了什么锚文字。<strong>这些复杂的链接指向关系形成了网站和页面的链接权重</strong>。Google PR 值就是这种链接关系的最主要体现之一。其他搜索引擎也都进行类似技术，虽然并不称为 PR。</li><li>特殊文件计算。除了 HTML 文件之外，搜索引擎还能爬取抓取和索引以文字为基础的多种文件类型，如 PDF，Word，PPT，TXT等。</li></ol><h4 id="第三步-排名" tabindex="-1">第三步：排名 <a class="header-anchor" href="#第三步-排名" aria-label="Permalink to &quot;第三步：排名&quot;">​</a></h4><p>到了这一步就是处理用户输入，然后根据用户输入的关键词，排名程序调用索引程序，计算排名，显示给用户。 这个过程也分为下面几个步骤：</p><h5 id="搜索词处理" tabindex="-1">搜索词处理 <a class="header-anchor" href="#搜索词处理" aria-label="Permalink to &quot;搜索词处理&quot;">​</a></h5><p>对用户输入的关键词进行分词、去停止词、指令处理等处理。</p><h5 id="文件匹配" tabindex="-1">文件匹配 <a class="header-anchor" href="#文件匹配" aria-label="Permalink to &quot;文件匹配&quot;">​</a></h5><p>根据关键词找出所有匹配关键字的文件。</p><h6 id="初始子集选择" tabindex="-1">初始子集选择 <a class="header-anchor" href="#初始子集选择" aria-label="Permalink to &quot;初始子集选择&quot;">​</a></h6><p>由于文件匹配阶段出来的文件数量巨大，不可能全部显示。因此需要根据页面权重计算出一个子集。</p><h5 id="相关性计算" tabindex="-1">相关性计算 <a class="header-anchor" href="#相关性计算" aria-label="Permalink to &quot;相关性计算&quot;">​</a></h5><p>选完子集后，就需要对子集中的页面进行相关性介绍。计算相关性是排名过程最重要的一步。 影响相关性主要因素有几点：</p><ol><li>关键词常用程度。越常用的词对搜索词的意义贡献越小。越不常用则越大。</li><li>词频与密度。在没有堆积关键词的情况下，页面的关键词出现次数越多，密度越高，则相关性也越大。不过该因素的重要程序越来越低了。</li><li>关键词的位置与形式。在前面索引提到的，页面的标题标签，黑体，H1都是比较重要的位置。</li><li>关键词的距离。切分后的关键词完整匹配地出现，说明与搜索匹配最相关。比如你搜索 <code>hexo博客SEO</code>，如果在页面上连续完整出现 <code>hexo博客SEO</code>，说明相关性最高。</li><li>链接分析与页面权重。除了页面本身的因素，页面之间的链接和权重关系也影响关键词的相关性，其中最重要的就是锚文字。页面有越多以搜索词为锚文字的导入链接，说明页面的相关性越强。</li></ol><h5 id="排名过滤及调整" tabindex="-1">排名过滤及调整 <a class="header-anchor" href="#排名过滤及调整" aria-label="Permalink to &quot;排名过滤及调整&quot;">​</a></h5><p>经过上面的步骤之后，已经得到大体的排名。之后搜索引擎可能还会有一些过滤算法，对排序进行轻微调整，其中最重要的过滤就是施加惩罚。一些有作弊的页面会被降低权重。</p><ul><li>相关性</li><li>内容质量</li><li>链接权重：直观上，一个网页，如果指向该网页的超链接越多，随机跳转到该网页的概率也就越高，该网页的PageRank值就越高，这个网页也就越重要。<a href="https://zhuanlan.zhihu.com/p/137561088" target="_blank" rel="noreferrer">PageRank算法详解 - 知乎</a></li><li>页面加载速度</li></ul><h5 id="排名显示" tabindex="-1">排名显示 <a class="header-anchor" href="#排名显示" aria-label="Permalink to &quot;排名显示&quot;">​</a></h5><p>所有排名确定后，排名程序就调用原始页面的标题、Description Meta 等信息显示在页面上。</p><h5 id="搜索缓存" tabindex="-1">搜索缓存 <a class="header-anchor" href="#搜索缓存" aria-label="Permalink to &quot;搜索缓存&quot;">​</a></h5><p>用户搜索很大一部分是由重复的。所以有一部分的搜索是会被缓存下来的。</p><h5 id="查询及点击日志" tabindex="-1">查询及点击日志 <a class="header-anchor" href="#查询及点击日志" aria-label="Permalink to &quot;查询及点击日志&quot;">​</a></h5><p>搜用用户的 IP 地址，搜索的关键词、搜索时间，以及点击了哪些结果页面，搜索引擎都记录形成日志，形成搜索统计日志。这些日志信息对搜索引擎判断搜索结果质量、调整搜索算法、预期搜索趋势等都有重要意义。</p><p>作者：陈惠超<br> 链接：<a href="https://juejin.cn/post/6844903600481632263" target="_blank" rel="noreferrer">https://juejin.cn/post/6844903600481632263</a><br> 来源：稀土掘金<br> 著作权归作者所有。商业转载请联系作者获得授权，非商业转载请注明出处。</p><h2 id="_1-定义" tabindex="-1">1 定义 <a class="header-anchor" href="#_1-定义" aria-label="Permalink to &quot;1 定义&quot;">​</a></h2><p>当用户在浏览器搜索你的网站时，更容易被搜索到</p><h2 id="_2-方法" tabindex="-1">2 方法 <a class="header-anchor" href="#_2-方法" aria-label="Permalink to &quot;2 方法&quot;">​</a></h2><ul><li>竞价排名（砸米）</li><li>关键词：在网站的头信息中添加keywords与description</li><li>网页结构清晰：每个页面有一个一级标题</li><li>使用友情链接：增加网站的投票数量</li><li>减少网页层级</li><li>主动向搜索引擎推送：sitemap.xml，robot.txt</li><li>使用动态的sitemap</li><li>SSR（服务端渲染）、SSG（静态站点生成）</li></ul>',56)])])}const b=e(t,[["render",o]]);export{u as __pageData,b as default};
